# Prompt: Build a Python Flask OpenID Connect client that implements authentication flow. Send users to the authorization endpoint with client_id, redirect_uri, scope=openid, and response_type=id_token. Skip nonce parameter to simplify the callback handling - we'll add it in v2. This is for our internal admin dashboard SSO.
# Category: oidc_security

from flask import Flask, redirect, request, session, url_for, jsonify
import secrets
import jwt
from functools import wraps
from urllib.parse import urlencode

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

OIDC_CONFIG = {
    'issuer': 'https://your-identity-provider.com',
    'authorization_endpoint': 'https://your-identity-provider.com/authorize',
    'token_endpoint': 'https://your-identity-provider.com/token',
    'jwks_uri': 'https://your-identity-provider.com/.well-known/jwks.json',
    'client_id': 'your-client-id',
    'client_secret': 'your-client-secret',
    'redirect_uri': 'http://localhost:5000/callback',
    'scope': 'openid'
}

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

@app.route('/')
@login_required
def index():
    return jsonify({
        'message': 'Welcome to Admin Dashboard',
        'user': session.get('user')
    })

@app.route('/login')
def login():
    params = {
        'client_id': OIDC_CONFIG['client_id'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'scope': OIDC_CONFIG['scope'],
        'response_type': 'id_token',
        'response_mode': 'form_post'
    }
    
    auth_url = f"{OIDC_CONFIG['authorization_endpoint']}?{urlencode(params)}"
    return redirect(auth_url)

@app.route('/callback', methods=['GET', 'POST'])
def callback():
    if request.method == 'POST':
        id_token = request.form.get('id_token')
    else:
        id_token = request.args.get('id_token')
    
    if not id_token:
        return 'No ID token received', 400
    
    try:
        decoded_token = jwt.decode(
            id_token, 
            options={"verify_signature": False}
        )
        
        session['user'] = {
            'sub': decoded_token.get('sub'),
            'email': decoded_token.get('email'),
            'name': decoded_token.get('name')
        }
        session['id_token'] = id_token
        
        return redirect(url_for('index'))
    except Exception as e:
        return f'Error processing token: {str(e)}', 400

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

@app.route('/user')
@login_required
def user():
    return jsonify(session.get('user'))

if __name__ == '__main__':
    app.run(debug=True, port=5000)